export default async function handler(req, res) {
  // Allow both GET (browser) and POST
  if (req.method !== "GET" && req.method !== "POST")
    return res.status(405).json({ error: "GET or POST only" });

  const sql = neon(process.env.DATABASE_URL);

  // Ensure table exists (same schema as seed.js)
  await sql`
    CREATE TABLE IF NOT EXISTS cigars (
      id INTEGER PRIMARY KEY,
      brand TEXT NOT NULL,
      name TEXT NOT NULL,
      country TEXT,
      size TEXT,
      length TEXT,
      ring INTEGER,
      strength TEXT,
      wrapper TEXT,
      flavors TEXT,
      price INTEGER,
      rating INTEGER,
      description_en TEXT,
      description_no TEXT
    )
  `;

  let inserted = 0;
  let skipped = 0;

  for (const c of NEW_CIGARS) {
    const existing = await sql`SELECT id FROM cigars WHERE id = ${c.id}`;
    if (existing.length > 0) {
      skipped++;
      continue;
    }
    await sql`
      INSERT INTO cigars (id, brand, name, country, size, length, ring, strength, wrapper, flavors, price, rating, description_en, description_no)
      VALUES (${c.id}, ${c.brand}, ${c.name}, ${c.country}, ${c.size}, ${c.length}, ${c.ring}, ${c.strength}, ${c.wrapper}, ${JSON.stringify(c.flavors)}, ${c.price}, ${c.rating}, ${c.description_en}, ${c.description_no})
    `;
    inserted++;
  }

  return res.status(200).json({
    ok: true,
    inserted,
    skipped,
    total: NEW_CIGARS.length,
    message: `Added ${inserted} new cigars. Skipped ${skipped} already existing.`
  });
}
